# 检查并安装所需的R包
required_packages <- c(
  "tidyverse",     # 数据处理和可视化
  "gtsummary",     # 统计表格生成
  "broom",         # 统计结果整理
  "corrplot",      # 相关矩阵可视化
  "medicaldata",   # 医学数据集
  "vcd"            # 可视化分类数据
)

# 检查并安装缺失的包
new_packages <- required_packages[!(required_packages %in% installed.packages()[,"Package"])]
if(length(new_packages)) install.packages(new_packages)

# 加载所有包
invisible(lapply(required_packages, library, character.only = TRUE))
